import React, { useState, useRef, useEffect } from "react";
import "./App.css";
import DatePicker from "react-datepicker";
import "react-datepicker/dist/react-datepicker.css";

export default function App() {
  const [msgs, setMsgs] = useState([]);
  const [input, setInput] = useState("");
  const [showDatePicker, setShowDatePicker] = useState(false);
  const [selectedDate, setSelectedDate] = useState(null);
  const [loading, setLoading] = useState(false);
  const [selectedOption, setSelectedOption] = useState(null);
  const [showConfirm, setShowConfirm] = useState(false);

  const chatEndRef = useRef(null);

  // Load chat history on first load
  useEffect(() => {
    const loadHistory = async () => {
      try {
        const res = await fetch("http://127.0.0.1:8000/api/history");
        const data = await res.json();
        setMsgs(data);
      } catch (err) {
        console.error("Failed to load history", err);
      }
    };

    loadHistory();
  }, []);

  // Auto scroll
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [msgs, loading]);

  const send = async (v = input) => {
    if (!v) return;

    setShowDatePicker(false);

    // Add user message immediately
    setMsgs((m) => [...m, { type: "user", text: v }]);

    setLoading(true);

    const res = await fetch("http://127.0.0.1:8000/api/chat", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ input: v }),
    });

    const d = await res.json();
    setLoading(false);

    if (d.response?.type === "welcome") {
      setMsgs((m) => [
        ...m,
        { type: "bot", text: d.response.message },
        { type: "buttons", options: d.response.options },
      ]);
    } else if (d.response?.type === "date_selection") {
      setShowDatePicker(true);
    } else if (d.response?.type === "date_buttons") {
      setSelectedOption(null);
      setMsgs((m) => [...m, { type: "buttons", options: d.response.options }]);
    } else {
      setMsgs((m) => [...m, { type: "bot", text: d.response }]);
    }

    setInput("");
  };

  const sendDate = () => {
    if (!selectedDate) return;

    const formatLocalDate = (date) => {
      const year = date.getFullYear();
      const month = String(date.getMonth() + 1).padStart(2, "0");
      const day = String(date.getDate()).padStart(2, "0");
      return `${year}-${month}-${day}`;
    };

    const formatted = formatLocalDate(selectedDate);

    setShowDatePicker(false);
    setSelectedDate(null);

    send(formatted);
  };

  const confirmClear = async () => {
    setMsgs([]);
    setSelectedDate(null);
    setSelectedOption(null);
    setShowDatePicker(false);
    setShowConfirm(false);

    await fetch("http://127.0.0.1:8000/api/reset", {
      method: "POST",
    });
  };

  return (
    <div className="app">
      <div className="header">
        <div className="title">🤖 Smart AI Assistant</div>
        <button className="clear-btn" onClick={() => setShowConfirm(true)}>
          Clear Chat
        </button>
      </div>

      <div className="chat">
        {msgs.map((m, i) =>
          m.type === "buttons" ? (
            <div key={i} className="button-group">
              {m.options.map((o) => (
                <button
                  key={o}
                  onClick={() => {
                    setSelectedOption(o);
                    send(o);
                  }}
                  className={selectedOption === o ? "active-btn" : ""}
                >
                  {o}
                </button>
              ))}
            </div>
          ) : (
            <div key={i} className={`msg ${m.type}`}>
              {m.text}
            </div>
          ),
        )}

        {loading && <div className="msg bot">Thinking...</div>}

        <div ref={chatEndRef} />
      </div>

      {showDatePicker && (
        <div className="date-picker-wrapper">
          <div className="date-picker-card">
            <DatePicker
              selected={selectedDate}
              onChange={(date) => setSelectedDate(date)}
              dateFormat="yyyy-MM-dd"
              minDate={new Date()}
              inline
            />

            <button className="confirm-btn" onClick={sendDate}>
              Confirm Date
            </button>
          </div>
        </div>
      )}

      {showConfirm && (
        <div className="modal-overlay">
          <div className="modal">
            <p>Are you sure you want to clear chat?</p>

            <div className="modal-actions">
              <button onClick={() => setShowConfirm(false)}>Cancel</button>

              <button className="danger" onClick={confirmClear}>
                Yes, Clear
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="input-bar">
        <input
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && send()}
          placeholder="Type something..."
        />
        <button onClick={() => send()}>Send</button>
      </div>
    </div>
  );
}
